import sys
import math

class Solution:
    def solve(self, nums):
        stack = []
        for num in nums:
            stack.append(num)
        output = 0
        while stack:
            if stack[-1] >= 2*100000:
                return output
            output += 1
            stack.pop()
        return output

if __name__ == '__main__':
    t = int(sys.stdin.readline().strip())
    nums = list(map(int, sys.stdin.readline().strip().split()))
    sol = Solution()
    print(sol.solve(nums))

